import { useState, useEffect, useCallback } from "react";
import { ethers } from "ethers";
import { USDC_ADDRESS, FLOWARC_ADDRESS } from "../contracts/abis";

function EmployerDashboard({ flowArc, usdc, address, isEmployer, setIsEmployer, notify }) {
  const [companyName, setCompanyName]     = useState("");
  const [balance, setBalance]             = useState("0");
  const [depositAmt, setDepositAmt]       = useState("");
  const [withdrawAmt, setWithdrawAmt]     = useState("");
  const [workers, setWorkers]             = useState([]);
  const [workerAddr, setWorkerAddr]       = useState("");
  const [workerName, setWorkerName]       = useState("");
  const [workerSalary, setWorkerSalary]   = useState("");
  const [loading, setLoading]             = useState(false);
  const [usdcBalance, setUsdcBalance]     = useState("0");

  const loadData = useCallback(async () => {
    if (!flowArc || !address) return;
    try {
      const emp = await flowArc.employers(address);
      if (emp.registered) {
        setBalance(ethers.utils.formatUnits(emp.balance, 6));
        const workerAddrs = await flowArc.getEmployerWorkers(address);
        const workerData = await Promise.all(
          workerAddrs.map(async (addr) => {
            const d = await flowArc.getWorkerDetails(address, addr);
            return {
              address: addr,
              name: d.name,
              salaryPerSecond: d.salaryPerSecond,
              active: d.active,
              earned: ethers.utils.formatUnits(d.earned, 6),
              monthlySalary: ethers.utils.formatUnits(d.salaryPerSecond.mul(30 * 24 * 3600), 6)
            };
          })
        );
        setWorkers(workerData);
      }
      if (usdc) {
        const bal = await usdc.balanceOf(address);
        setUsdcBalance(ethers.utils.formatUnits(bal, 6));
      }
    } catch (e) {
      console.error(e);
    }
  }, [flowArc, usdc, address]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 10000);
    return () => clearInterval(interval);
  }, [loadData]);

  const registerEmployer = async () => {
    if (!companyName) return notify("Enter company name", "error");
    setLoading(true);
    try {
      const tx = await flowArc.registerEmployer(companyName);
      await tx.wait();
      setIsEmployer(true);
      notify(`Company "${companyName}" registered!`);
      loadData();
    } catch (e) {
      notify(e.message, "error");
    }
    setLoading(false);
  };

  const depositFunds = async () => {
    if (!depositAmt) return notify("Enter amount", "error");
    setLoading(true);
    try {
      const amount = ethers.utils.parseUnits(depositAmt, 6);
      const allowance = await usdc.allowance(address, FLOWARC_ADDRESS);
      if (allowance.lt(amount)) {
        const approveTx = await usdc.approve(FLOWARC_ADDRESS, ethers.constants.MaxUint256);
        await approveTx.wait();
      }
      const tx = await flowArc.depositFunds(amount);
      await tx.wait();
      notify(`Deposited ${depositAmt} USDC!`);
      setDepositAmt("");
      loadData();
    } catch (e) {
      notify(e.message, "error");
    }
    setLoading(false);
  };

  const withdrawFunds = async () => {
    if (!withdrawAmt) return notify("Enter amount", "error");
    setLoading(true);
    try {
      const tx = await flowArc.withdrawFunds(ethers.utils.parseUnits(withdrawAmt, 6));
      await tx.wait();
      notify(`Withdrawn ${withdrawAmt} USDC!`);
      setWithdrawAmt("");
      loadData();
    } catch (e) {
      notify(e.message, "error");
    }
    setLoading(false);
  };

  const addWorker = async () => {
    if (!workerAddr || !workerName || !workerSalary) return notify("Fill all fields", "error");
    setLoading(true);
    try {
      const tx = await flowArc.addWorker(workerAddr, workerName, ethers.utils.parseUnits(workerSalary, 6));
      await tx.wait();
      notify(`Worker "${workerName}" added!`);
      setWorkerAddr(""); setWorkerName(""); setWorkerSalary("");
      loadData();
    } catch (e) {
      notify(e.message, "error");
    }
    setLoading(false);
  };

  const removeWorker = async (workerAddress) => {
    setLoading(true);
    try {
      const tx = await flowArc.removeWorker(workerAddress);
      await tx.wait();
      notify("Worker removed!");
      loadData();
    } catch (e) {
      notify(e.message, "error");
    }
    setLoading(false);
  };

  if (!isEmployer) return (
    <div style={styles.card}>
      <h2 style={styles.cardTitle}>Register as Employer</h2>
      <p style={styles.cardSub}>Set up your company to start paying workers in USDC</p>
      <input
        style={styles.input}
        placeholder="Company Name"
        value={companyName}
        onChange={e => setCompanyName(e.target.value)}
      />
      <button style={styles.btn} onClick={registerEmployer} disabled={loading}>
        {loading ? "Registering..." : "Register Company →"}
      </button>
    </div>
  );

  return (
    <div>
      {/* ── Balance Card ── */}
      <div style={styles.balanceCard}>
        <div>
          <div style={styles.balanceLabel}>Payroll Vault Balance</div>
          <div style={styles.balanceAmt}>{parseFloat(balance).toFixed(2)} <span style={styles.usdc}>USDC</span></div>
        </div>
        <div>
          <div style={styles.balanceLabel}>Your Wallet Balance</div>
          <div style={styles.balanceAmt}>{parseFloat(usdcBalance).toFixed(2)} <span style={styles.usdc}>USDC</span></div>
        </div>
        <div>
          <div style={styles.balanceLabel}>Active Workers</div>
          <div style={styles.balanceAmt}>{workers.filter(w => w.active).length}</div>
        </div>
      </div>

      {/* ── Deposit / Withdraw ── */}
      <div style={styles.row}>
        <div style={styles.card}>
          <h3 style={styles.cardTitle}>💰 Deposit USDC</h3>
          <input style={styles.input} placeholder="Amount" type="number" value={depositAmt} onChange={e => setDepositAmt(e.target.value)} />
          <button style={styles.btn} onClick={depositFunds} disabled={loading}>Deposit</button>
        </div>
        <div style={styles.card}>
          <h3 style={styles.cardTitle}>🏦 Withdraw USDC</h3>
          <input style={styles.input} placeholder="Amount" type="number" value={withdrawAmt} onChange={e => setWithdrawAmt(e.target.value)} />
          <button style={{ ...styles.btn, background: "#ff4d4f" }} onClick={withdrawFunds} disabled={loading}>Withdraw</button>
        </div>
      </div>

      {/* ── Add Worker ── */}
      <div style={styles.card}>
        <h3 style={styles.cardTitle}>➕ Add Worker</h3>
        <div style={styles.inputRow}>
          <input style={styles.input} placeholder="Wallet Address (0x...)" value={workerAddr} onChange={e => setWorkerAddr(e.target.value)} />
          <input style={styles.input} placeholder="Worker Name" value={workerName} onChange={e => setWorkerName(e.target.value)} />
          <input style={styles.input} placeholder="Monthly Salary (USDC)" type="number" value={workerSalary} onChange={e => setWorkerSalary(e.target.value)} />
        </div>
        <button style={styles.btn} onClick={addWorker} disabled={loading}>
          {loading ? "Adding..." : "Add Worker →"}
        </button>
      </div>

      {/* ── Workers List ── */}
      <div style={styles.card}>
        <h3 style={styles.cardTitle}>👷 Workers</h3>
        {workers.length === 0 && <p style={styles.empty}>No workers added yet</p>}
        {workers.map(w => (
          <div key={w.address} style={styles.workerRow}>
            <div>
              <div style={styles.workerName}>{w.name} {!w.active && <span style={styles.inactive}>Inactive</span>}</div>
              <div style={styles.workerAddr}>{w.address.slice(0, 10)}...{w.address.slice(-6)}</div>
              <div style={styles.workerSalary}>Monthly: {parseFloat(w.monthlySalary).toFixed(2)} USDC</div>
            </div>
            <div style={styles.workerRight}>
              <div style={styles.earned}>Earned: {parseFloat(w.earned).toFixed(4)} USDC</div>
              {w.active && (
                <button style={styles.removeBtn} onClick={() => removeWorker(w.address)} disabled={loading}>
                  Remove
                </button>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  balanceCard:  { display: "flex", justifyContent: "space-between", background: "#5865f2", borderRadius: "16px", padding: "30px", marginBottom: "20px" },
  balanceLabel: { fontSize: "13px", color: "rgba(255,255,255,0.7)", marginBottom: "8px" },
  balanceAmt:   { fontSize: "28px", fontWeight: "800", color: "#fff" },
  usdc:         { fontSize: "16px", fontWeight: "400" },
  row:          { display: "flex", gap: "20px", marginBottom: "20px" },
  card:         { background: "#1a1a2e", borderRadius: "16px", padding: "24px", marginBottom: "20px", flex: 1 },
  cardTitle:    { fontSize: "18px", fontWeight: "700", marginBottom: "8px", color: "#fff" },
  cardSub:      { color: "#888", marginBottom: "20px" },
  input:        { width: "100%", background: "#0a0a0f", border: "1px solid #2a2a3e", borderRadius: "8px", padding: "12px", color: "#fff", fontSize: "14px", marginBottom: "12px", boxSizing: "border-box" },
  inputRow:     { display: "flex", flexDirection: "column" },
  btn:          { className: "btn-gold" },
  workerRow:    { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "16px", background: "#0a0a0f", borderRadius: "8px", marginBottom: "10px" },
  workerName:   { fontWeight: "700", marginBottom: "4px" },
  workerAddr:   { fontSize: "12px", color: "#888" },
  workerSalary: { fontSize: "13px", color: "#5865f2", marginTop: "4px" },
  workerRight:  { textAlign: "right" },
  earned:       { fontSize: "13px", color: "#00c48c", marginBottom: "8px" },
  removeBtn:    { background: "#ff4d4f", color: "#fff", border: "none", padding: "6px 14px", borderRadius: "6px", cursor: "pointer", fontSize: "12px" },
  inactive:     { fontSize: "11px", background: "#ff4d4f", padding: "2px 6px", borderRadius: "4px", marginLeft: "8px" },
  empty:        { color: "#888", textAlign: "center", padding: "20px" },
};

export default EmployerDashboard;
